# Helper to compile with arbitrary (pre-validated) flags
sub _compile_with_flags {
    my ($pattern, $flags) = @_;
    # We construct the inline flag group: (?FLAGS:PATTERN)
    # This is safe because $flags has been validated to contain only [imsx]
    my $combined = "(?${flags}:${pattern})";
    no re 'eval';
    return qr/$combined/;
}

# -----------------------------------------------------------------------------
# Match a string against a safely compiled pattern
# Returns match result with captures
# -----------------------------------------------------------------------------
sub match {
    my ($self, $string, $pattern_str, $flags) = @_;

    if (!defined $string) {
        return { success => 0, error => "Input string is undefined" };
    }

    # Compile the pattern safely
    my $compile_result = $self->compile_pattern($pattern_str, $flags);
    unless ($compile_result->{success}) {
        return $compile_result;
    }

    my $regex = $compile_result->{regex};

