    my $matched;
    my @captures;
    eval {
        local $SIG{ALRM} = sub { die "Regex match timed out (possible ReDoS)\n" };
        alarm($self->{match_timeout});

        no re 'eval';
        if ($string =~ $regex) {
            $matched = 1;
            # Collect numbered captures
            no strict 'refs';
            for my $i (1 .. 20) {
                last unless defined ${ $i };
                push @captures, ${ $i };
            }
        } else {
            $matched = 0;
        }

        alarm(0);
    };
    alarm(0);

    if ($@) {
        my $error = $@;
        chomp $error;
        return { success => 0, error => $error };
    }

    return {
        success  => 1,
        matched  => $matched,
        captures => \@captures,
    };
}

# -----------------------------------------------------------------------------
# Validate a string against a named validation rule from configuration
# -----------------------------------------------------------------------------
sub validate {
    my ($self, $string, $rule_name, $rules_config) = @_;

    unless (exists $rules_config->{$rule_name}) {
        return { success => 0, error => "Unknown validation rule: '$rule_name'" };
    }

    my $rule = $rules_config->{$rule_name};
    my $pattern = $rule->{pattern};
    my $flags   = $rule->{flags} // '';
    my $message = $rule->{message} // "Validation failed for rule '$rule_name'";

    my $result = $self->match($string, $pattern, $flags);

    if (!$result->{success}) {
        return $result;
    }

    if ($result->{matched}) {
        return { success => 1, valid => 1, rule => $rule_name };
    } else {
        return { success => 1, valid => 0, rule => $rule_name, message => $message };
    }
}

